import { Module, type Provider } from '@nestjs/common';
import {
  createLoopbackMiddleware,
  PollChangeSource,
  SYNC_CHANGE_SOURCE,
  type ChangeMiddleware,
  type DetectionConfig,
  type ILoopbackFingerprintStore,
  type PollFetchCallback,
} from '@shared/subsystems/sync';
import { Opportunity } from '../domain/opportunity/opportunity.entity';

/**
 * Per-entity adapter-callback token. The consumer feature module provides
 * the `PollFetchCallback<Opportunity>` value at this token; this
 * module declares the symbol and consumes it in the factory.
 */
export const OPPORTUNITY_SYNC_ADAPTER = 'OPPORTUNITY_SYNC_ADAPTER' as const;

/**
 * Optional loopback fingerprint-store token. When bound, the factory
 * composes `createLoopbackMiddleware(store)` as the outermost middleware.
 */
export const OPPORTUNITY_SYNC_LOOPBACK_STORE = 'OPPORTUNITY_SYNC_LOOPBACK_STORE' as const;

/**
 * Detection config inlined from the entity YAML. Validated at codegen
 * time by `DetectionConfigSchema`; passed by-value to the primitive at
 * construction. Edit the YAML, not this constant.
 */
const detectionConfig: DetectionConfig = {
  "mode": "poll",
  "poll": {
    "cursor": {
      "kind": "systemModstamp",
      "field": "SystemModstamp"
    }
  },
  "mapping": [
    {
      "source": "Id",
      "target": "external_id"
    },
    {
      "source": "Name",
      "target": "name"
    },
    {
      "source": "Amount",
      "target": "amount",
      "transform": "decimal-string"
    },
    {
      "source": "CloseDate",
      "target": "expected_close_date",
      "transform": "date-iso"
    },
    {
      "source": "OwnerId",
      "target": "owner_id"
    }
  ],
  "filters": [
    {
      "field": "IsDeleted",
      "op": "eq",
      "value": false
    },
    {
      "field": "StageName",
      "op": "neq",
      "value": "Closed Lost"
    }
  ]
};

const syncSourceProvider: Provider = {
  provide: SYNC_CHANGE_SOURCE,
  useFactory: (
    adapter: PollFetchCallback<Opportunity>,
    loopbackStore: ILoopbackFingerprintStore<Opportunity> | null,
  ) => {
    const middlewares: ChangeMiddleware<Opportunity>[] = loopbackStore
      ? [createLoopbackMiddleware<Opportunity>(loopbackStore)]
      : [];
    return new PollChangeSource<Opportunity>({
      adapter,
      config: detectionConfig,
      middlewares,
    });
  },
  inject: [
    OPPORTUNITY_SYNC_ADAPTER,
    { token: OPPORTUNITY_SYNC_LOOPBACK_STORE, optional: true },
  ],
};

@Module({
  providers: [syncSourceProvider],
  exports: [SYNC_CHANGE_SOURCE],
})
export class OpportunitySyncSourceModule {}
